export const getInitialLanguage = (): LanguageCode => {
  const code = Localization.getLocales()[0]?.languageCode;
  if (code === 'fr' || code === 'ar') return code;
  return 'en';
};

export const applyTextDirection = (language: LanguageCode) => {
  const shouldBeRtl = language === 'ar';
  if (I18nManager.isRTL !== shouldBeRtl) {
    I18nManager.allowRTL(shouldBeRtl);
    I18nManager.forceRTL(shouldBeRtl);
  }
};

export const translate = (language: LanguageCode, key: string) => extraTranslations[language][key] ?? translations[language][key] ?? extraTranslations.en[key] ?? translations.en[key] ?? key;






